chkPostPress:
function chkPostPress(ppSection, ppType) {

		var size_type = $('size_type').value; //규격형
		var paper_code = $('paper_code').value;


		//아쿠아사틴256g,아르미 울트라화이트 310g,인버코트 350g,랑데뷰 내츄럴 310g,스노우지 백색 300g,반누보 화이트 204g,반누보 스노우화이트 227g,반누보 화이트 250g,아르미 울트라화이트 230g
		var dbak_paper_arr = Array('AQS256W00','ARM310W00','INV350MT0','RDV310N00','SNW300W00','VNV186W00','VNV227SW0','VNV233W00','ARM230W00');

		if (category_code == 'CNC2000') {
			if (paper_code == 'RBE359W00' || paper_code == 'VVT359W00' || paper_code == 'BKN350BL0' || paper_code == 'BKN380BL0') { //러버화이트,벨벳화이트,매트블랙,매트블랙 380
				if ($('chk_is_epoxy').checked == true) {
					alert("선택한 용지는 에폭시를 할 수 없습니다.");
					$('chk_is_epoxy').checked = false;
					return false;
				}
			}

			print1.optionPrintColorType();

		}


		if(!dbak_paper_arr.includes(paper_code) ){//디지털 박 가능 용지가 아닌경우
			if( $('chk_is_dbak').checked == true) { //디지털 박
				alert("디지털 박이 불가능한 용지입니다.");
				$('chk_is_dbak').checked = false;
				$('pnl_dbak').hide();
				return false;
			}

		}
		if((ppType == "dbak" && $('chk_is_bak').checked == true && $('chk_is_dbak').checked == true)){
			alert("디지털 박은 박과 동시에 주문 하실 수 없습니다.");
			$('chk_is_dbak').checked = false; $('dbak_amt').value = 0; $('dbak_dp_amt').value = 0;
				return false;
		}
		if((ppType == "bak" && $('chk_is_bak').checked == true && $('chk_is_dbak').checked == true)){
			alert("박은 디지털 박과 동시에 주문 하실 수 없습니다.");
			$('chk_is_bak').checked = false; $('bak_amt').value = 0; $('bak_dp_amt').value = 0;
				return false;
		}
		if (!staff_id) {
			if(category_code == 'CNC2000' && dbak_paper_arr.includes(paper_code) ){//디지털 박 가능 용지
				if( ppType=="bak" && $('chk_is_bak').checked == true) { //박
				//팝업
					dBakPreview();
				}

			}
		}
		if (category_code.match('CVS') && size_type == 'SZT10' && ppType == 'domusong') { //초대장
			alert('초대장 규격형은 후가공 도무송을 뺄 수 없습니다.');
			$('chk_is_domusong').checked = true;
			return false;
		}

		if ((category_code.match('CNC6000') || category_code.match('CVS6000')) && ppType == 'epoxy') { //에폭시명함,초대장
			if($j("#chk_is_epoxy").attr('checked') == false){
				alert('에폭시명함,초대장은 에폭시 후가공을 뺄 수 없습니다.');
				$('chk_is_epoxy').checked = true;
				return false;
			}
		}
		if ((category_code.match('CNC8000') ) && ppType == 'dbak') { //디지털박명함, 디지털 박
			if($j("#chk_is_dbak").attr('checked') == false){
				alert('디지털박 명함은 디지털 박 후가공을 뺄 수 없습니다.');
				$('chk_is_dbak').checked = true;
				return false;
			}
		}
		if (ppType == 'numbering' && (paper_code == 'NEC350BL0' || paper_code == 'BKN350BL0' || paper_code == 'BKN380BL0')) {
			alert('해당 용지는 용지색상이 어두워서 넘버링이 잘 안보입니다.\n\n넘버링이 필요하신분은 별도로 상담해주세요.');
			$('chk_is_numbering').checked = false;
			return false;
		}

		if (ppType == 'numbering' && (paper_code == 'VVT359W00') ) { //넘버링 + 벨벳 화이트 359g 
			alert("벨벳 화이트 359g 용지는 넘버링을 할 수 없습니다.");
			$('chk_is_numbering').checked = false;
		}

		if (ppType == 'epoxy') {
			ppEpoxySelectCheck();
		}

		chkVar = $j("#chk_is_" + ppType).attr('checked');

		if (ppSection == "1") {
			if (chkVar) {
				chkVar2 = true;
			} else {
				chkVar2 = false;
			}
		} else {
			if (chkVar) {
				chkVar2 = false;
			} else {
				chkVar2 = true;
			}
		}

		if ((category_code == "CNC5000" || category_code == "CNC3000") && ppType == 'guidori') {
			$('chk_is_guidori').checked = true;
			chkVar2 = true;
		}

		if (chkVar2) {
			$j("#pnl_" + ppType).show();
			$j("#chk_is_" + ppType).attr('checked', 'true');
			$j("#chk_is_" + ppType + "2").attr('checked', 'true');
		} else {
			$j("#pnl_" + ppType).hide();
			$j("#chk_is_" + ppType).attr('checked', '');
			$j("#chk_is_" + ppType + "2").attr('checked', '');
		}

		setIsPostpress(ppType); //후가공 DB data 가져오기
		product1.printEstimate();
		isTodayPPCheck();

		//후가공 미리보기 이미지 숨김
		if (staff_id) {
			pp_preview_layer_img_hide(ppType);
		} else {
			pp_preview_layer_img_show(ppType);
		}

		//선택시 귀도리 초기화값
		if (ppType == 'guidori') {
			chgGuidoriType();
		}

		expect_release_date(); //예상출고일

	}

chgPaperSize:
function chgPaperSize() {

		product1.changePaperSize();

		if ($('chk_is_osi').checked == true) {
			chgOsiNum();
		}

		if ($('chk_is_bak').checked == true) {
			initExistBakDongpan(1);
			initExistBakDongpan(2);
			initExistBakDongpan(3);
		}

		if ($('chk_is_ap').checked == true) {
			initExistAPDongpan(1);
			initExistAPDongpan(2);
			initExistAPDongpan(3);
		}

		if ($('chk_is_domusong').checked == true) {
			initExistMoghyeong(); //보유목형 초기화
		}


		chgIsToday(); //당일판체크
		chgIsSat(); //토요판체크

		if (category_code.match('CVS') && $("size_type").value == 'SZT10') { //규격형만
			productVideoPreview(); //동영상가이드 미리보기
		} else {
			productSizePreview(); //제품사이즈 미리보기
		}

	}

chgSizeType:
function chgSizeType() {

		var checks = $('size_type').value;

		if (checks == 'SZT10') {
			$('sp_x_size_change').show();
			$('sp_y_size_change').show();
			$('sp_size_change_view').show();
			$('size_change').value = 'STC10';
			$('etc2').value = 'STC10';

			$j('#btn_preview').show(); //미리보기 버튼
			$j('#btn_download').show(); //다운로드 버튼

			$("paper_size").show();

			$j('#cut_x_size').css('background', '#FFFFFF'); //흰색변경
			$j('#cut_y_size').css('background', '#FFFFFF'); //흰색변경

			$j('#cut_x_size').attr('readonly', true);
			$j('#cut_y_size').attr('readonly', true);

			if (category_code == 'CNC3000' || category_code == 'CNC5000') { //카드,투명명함
				$('guidori_position1').checked = true;
				$('guidori_position2').checked = true;
				$('guidori_position3').checked = true;
				$('guidori_position4').checked = true;
			}
		} else {
			$('sp_x_size_change').hide();
			$('sp_y_size_change').hide();
			$('sp_size_change_view').hide();
			$('size_change').value = '';
			$('etc2').value = '';

			$j('#btn_preview').hide(); //미리보기 버튼
			$j('#btn_download').hide(); //다운로드 버튼

			$("paper_size").hide();

			$('cut_x_size').value = '90';
			$('cut_y_size').value = '50';
			$('work_x_size').value = '0';
			$('work_y_size').value = '0';

			$j('#cut_x_size').css('background', '#FFFF66'); //노란색변경
			$j('#cut_y_size').css('background', '#FFFF66'); //노란색변경

			$j('#cut_x_size').attr('readonly', false);
			$j('#cut_y_size').attr('readonly', false);
		}

		product1.changePaperSize();

		chgIsToday(); //당일판체크
		chgIsSat(); //토요판체크

		productSizePreview(); //제품사이즈 미리보기

	}

order_price_detail:
function order_price_detail(){

		if(staff_id != '' && staff_id != 'guest'){//관리자만 표시//
			var paper_price = $('paper_price').value;
			var plate_price = $('plate_price').value;
			var print_price = $('print_price').value;
			var postpress_amt = $('postpress_amt').value;
			var design_price = $('design_price').value;

			var html = "";
			html += "<table border='0' align='left' width='100' cellspacing='1' cellpadding='1' bgcolor='#CCCCCC'>";
			html += "<tr bgcolor='#FFFFFF'><td>용지비 : </td><td align='right'>"+numberFormat(paper_price)+"</td></tr>";
			html += "<tr bgcolor='#FFFFFF'><td>판비용 : </td><td align='right'>"+numberFormat(plate_price)+"</td></tr>";
			html += "<tr bgcolor='#FFFFFF'><td>인쇄비 : </td><td align='right'>"+numberFormat(print_price)+"</td></tr>";
			html += "<tr bgcolor='#FFFFFF'><td>후가공 : </td><td align='right'>"+numberFormat(postpress_amt)+"</td></tr>";
			html += "<tr bgcolor='#FFFFFF'><td>디자인 : </td><td align='right'>"+numberFormat(design_price)+"</td></tr>";
			html += "</table>";
			if(category_code.indexOf("COR")>=0){html='';}
			$j('#pnl_order_price_detail').html(html);
		}

		var is_auth_view_order_amt = '';//금액노출권한
		if(is_auth_view_order_amt == '1'){
			$('pnl_total_price_hide').hide();
			$('pnl_order_price_detail').hide();
		}


	}
